import{_ as e,o as l,c as s,a2 as n}from"./chunks/framework.tNPPebLH.js";const u=JSON.parse('{"title":"完整使用手册","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide.md","filePath":"user-guide.md","lastUpdated":1783841449000}'),i={name:"user-guide.md"};function t(r,a,d,o,p,h){return l(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="完整使用手册" tabindex="-1">完整使用手册 <a class="header-anchor" href="#完整使用手册" aria-label="Permalink to &quot;完整使用手册&quot;">​</a></h1><h2 id="studio-和桌宠的职责" tabindex="-1">Studio 和桌宠的职责 <a class="header-anchor" href="#studio-和桌宠的职责" aria-label="Permalink to &quot;Studio 和桌宠的职责&quot;">​</a></h2><p>PetPack Studio 是导入、校验、预览和发布工具；生成的桌宠是独立运行时。桌宠只读取相邻的 <code>petpack.bundle</code>，不要求 Codex 正在运行，也不读取 Codex 的宠物目录。</p><h2 id="导入来源" tabindex="-1">导入来源 <a class="header-anchor" href="#导入来源" aria-label="Permalink to &quot;导入来源&quot;">​</a></h2><h3 id="本地文件夹" tabindex="-1">本地文件夹 <a class="header-anchor" href="#本地文件夹" aria-label="Permalink to &quot;本地文件夹&quot;">​</a></h3><p>选择宠物根目录，或选择只包含一个宠物子目录的父目录。Studio 会查找 <code>pet.json</code>，再读取清单引用的 PNG/WebP 图集。</p><h3 id="zip-或单个文件" tabindex="-1">ZIP 或单个文件 <a class="header-anchor" href="#zip-或单个文件" aria-label="Permalink to &quot;ZIP 或单个文件&quot;">​</a></h3><p>ZIP 可以把宠物文件放在根目录或一个顶层文件夹内。ZIP 中存在多个宠物、路径穿越或绝对路径时会被拒绝。</p><p>选择 <code>pet.json</code> 或 spritesheet 文件时，Studio 使用它所在的目录作为宠物根目录。</p><h3 id="petdex" tabindex="-1">Petdex <a class="header-anchor" href="#petdex" aria-label="Permalink to &quot;Petdex&quot;">​</a></h3><p>输入 Petdex slug 或 <code>petdex.dev/pets/&lt;slug&gt;</code> 页面地址。Studio 只从 Petdex 官方资产域读取清单和图集，不执行页面脚本。</p><h2 id="校验结果" tabindex="-1">校验结果 <a class="header-anchor" href="#校验结果" aria-label="Permalink to &quot;校验结果&quot;">​</a></h2><p>校验区域分为三类信息：</p><table tabindex="0"><thead><tr><th>项目</th><th>作用</th></tr></thead><tbody><tr><td>图集尺寸</td><td>判断 Codex v2、Codex/Petdex v1 或兼容 9 行格式。</td></tr><tr><td>帧占用</td><td>确认要求使用的单元格有可见像素，保留单元格完全透明。</td></tr><tr><td>清单文件</td><td>检查 ID、显示名称、版本声明和图集路径。</td></tr></tbody></table><p>错误会阻断发布；警告表示格式可以运行，但可能不是标准尺寸或缺少建议字段。</p><h2 id="动画预览" tabindex="-1">动画预览 <a class="header-anchor" href="#动画预览" aria-label="Permalink to &quot;动画预览&quot;">​</a></h2><p>状态按钮对应 9 个标准动作：</p><ol><li>待机；</li><li>向右移动；</li><li>向左移动；</li><li>挥手；</li><li>跳跃；</li><li>失落；</li><li>等待；</li><li>工作；</li><li>检查。</li></ol><p>Codex v2 还包含 16 个顺时针注视方向。独立桌宠会根据指针相对位置选择注视帧，指针离开或进入中心死区后恢复待机。</p><h2 id="桌面试玩" tabindex="-1">桌面试玩 <a class="header-anchor" href="#桌面试玩" aria-label="Permalink to &quot;桌面试玩&quot;">​</a></h2><p>“桌面试玩”使用当前导入包创建临时透明窗口，适合发布前确认：</p><ul><li>角色没有裁切；</li><li>缩放后仍完整可见；</li><li>底部把手能够拖动；</li><li>工具栏仅在光标进入宠物时出现；</li><li>动画帧没有跳动、方向反转或背景残留。</li></ul><p>试玩窗口关闭后不会生成发布文件。</p><h2 id="应用信息" tabindex="-1">应用信息 <a class="header-anchor" href="#应用信息" aria-label="Permalink to &quot;应用信息&quot;">​</a></h2><p>发布前可以修改：</p><ul><li><strong>应用 ID</strong>：用于输出文件夹、程序名和包标识；建议使用小写字母、数字和连字符。</li><li><strong>显示名称</strong>：显示在桌宠窗口、托盘和说明文件中。</li><li><strong>描述</strong>：写入导出清单，便于记录角色来源和用途。</li></ul><p>修改这些字段不会覆盖原始宠物目录。</p><h2 id="当前平台成品" tabindex="-1">当前平台成品 <a class="header-anchor" href="#当前平台成品" aria-label="Permalink to &quot;当前平台成品&quot;">​</a></h2><p>当前平台成品包含本机原生运行时。Windows 生成 EXE，macOS 生成 App，Linux 生成可执行文件。Studio 同时输出便携目录和 ZIP。</p><p>适用场景：</p><ul><li>自己在当前设备使用；</li><li>分发给相同操作系统和 CPU 架构的用户；</li><li>发布前快速验证最终运行时。</li></ul><h2 id="跨平台构建包" tabindex="-1">跨平台构建包 <a class="header-anchor" href="#跨平台构建包" aria-label="Permalink to &quot;跨平台构建包&quot;">​</a></h2><p>跨平台构建包用于在目标设备生成原生运行时。它不包含完整 Studio 界面，只包含：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>petpack-cross-platform/</span></span>
<span class="line"><span>├── petpack.bundle/</span></span>
<span class="line"><span>├── build-request.json</span></span>
<span class="line"><span>├── builders/</span></span>
<span class="line"><span>├── START-HERE.html</span></span>
<span class="line"><span>├── BUILD-WINDOWS.cmd</span></span>
<span class="line"><span>├── BUILD-MAC.command</span></span>
<span class="line"><span>├── BUILD-LINUX.sh</span></span>
<span class="line"><span>├── build-here.ps1</span></span>
<span class="line"><span>├── build-here.sh</span></span>
<span class="line"><span>└── README.md</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>目标设备先打开 <code>START-HERE.html</code>，再双击对应系统的一键入口；成功后会自动打开 <code>output/</code>，其中包含原生桌宠目录和 ZIP。构建器缺失时会在首次运行自动下载；失败时指引页会提供手动下载入口。详见<a href="./CROSS_PLATFORM">跨平台构建与分发</a>。</p><h2 id="独立桌宠交互" tabindex="-1">独立桌宠交互 <a class="header-anchor" href="#独立桌宠交互" aria-label="Permalink to &quot;独立桌宠交互&quot;">​</a></h2><h3 id="拖动" tabindex="-1">拖动 <a class="header-anchor" href="#拖动" aria-label="Permalink to &quot;拖动&quot;">​</a></h3><p>按住宠物底部三点把手移动。多显示器和高 DPI 环境使用逻辑坐标定位，调整大小后会把窗口限制在当前显示器可见范围内。</p><h3 id="缩放" tabindex="-1">缩放 <a class="header-anchor" href="#缩放" aria-label="Permalink to &quot;缩放&quot;">​</a></h3><p>悬停工具栏的 <code>−</code> 和 <code>＋</code> 以 15% 为步长缩放，范围为 70%–140%。托盘菜单提供小、标准和大三档。缩放值保存在当前桌宠的本地 WebView 存储中。</p><h3 id="动作" tabindex="-1">动作 <a class="header-anchor" href="#动作" aria-label="Permalink to &quot;动作&quot;">​</a></h3><p>工具栏提供挥手和跳跃；托盘菜单还可以切换待机、工作等状态。动作完成后会返回正常循环。</p><h3 id="置顶" tabindex="-1">置顶 <a class="header-anchor" href="#置顶" aria-label="Permalink to &quot;置顶&quot;">​</a></h3><p>桌宠默认置顶。点击圆点按钮或使用托盘菜单切换置顶状态。</p><h3 id="退出" tabindex="-1">退出 <a class="header-anchor" href="#退出" aria-label="Permalink to &quot;退出&quot;">​</a></h3><p>点击悬停工具栏的关闭按钮或托盘“退出”。任务栏中没有桌宠按钮是正常行为。</p><h2 id="studio-窗口行为" tabindex="-1">Studio 窗口行为 <a class="header-anchor" href="#studio-窗口行为" aria-label="Permalink to &quot;Studio 窗口行为&quot;">​</a></h2><p>Studio 是普通桌面程序：</p><ul><li>最小化后保留在任务栏；</li><li>点击任务栏图标恢复；</li><li>点击关闭按钮直接结束 Studio 进程；</li><li>Studio 本身不常驻托盘。</li></ul><h2 id="输出目录说明" tabindex="-1">输出目录说明 <a class="header-anchor" href="#输出目录说明" aria-label="Permalink to &quot;输出目录说明&quot;">​</a></h2><p>不要只发送桌宠可执行文件。运行程序必须和 <code>petpack.bundle</code> 保持相对位置。推荐始终发送 Studio 生成的完整 ZIP。</p><p>重新打包同一个宠物时，选择空输出目录或先移走旧产物，避免接收者混用不同版本的运行时和资源。</p>`,52)])])}const b=e(i,[["render",t]]);export{u as __pageData,b as default};
